sql:
SELECT location_name 
FROM locations 
WHERE location_id IN (SELECT location_id FROM weather_stations);

SELECT COUNT(DISTINCT created_by)
FROM reports
WHERE location_id = 0;

external_knowledge:
- "beacons" refers to the top locations in terms of activity;
- "shone the brightest" metaphorically represents having the highest number of reports;
- "attracting the most beams of published reports" means these locations have the most reports published within the last month.

sql:
SELECT u.user_name, l.location_name
FROM users AS u
JOIN locations AS l ON u.user_id = l.location_id;

SELECT location_name 
FROM locations 
WHERE elevation = (SELECT MAX(elevation) FROM locations);

SELECT *
FROM locations
WHERE elevation < (SELECT AVG(elevation) FROM locations);
